func solve(nums []int64) int64 {
    if len(nums) == 0 {
        return 0
    }

    // Precompute primes up to the maximum index in nums using Sieve of Eratosthenes
    maxIndex := len(nums) - 1
    isPrime := make([]bool, maxIndex+1)
    for i := 2; i <= maxIndex; i++ {
        isPrime[i] = true
    }

    for i := 2; i*i <= maxIndex; i++ {
        if isPrime[i] {
            for j := i * i; j <= maxIndex; j += i {
                isPrime[j] = false
            }
        }
    }

    var sumA, sumB int64
    for i, num := range nums {
        if i >= 2 && isPrime[i] {
            sumA += num
        } else {
            sumB += num
        }
    }

    diff := sumA - sumB
    if diff < 0 {
        return -diff
    }
    return diff
}
