package main

func solve(nums []int64) int64 {
    totalSum := int64(0)
    for _, num := range nums {
        totalSum += num
    }

    n := len(nums)
    if n == 0 {
        return 0
    }

    isPrime := make([]bool, n)
    for i := 0; i < n; i++ {
        if i < 2 {
            isPrime[i] = false
        } else {
            isPrime[i] = true
        }
    }

    for i := 2; i*i < n; i++ {
        if isPrime[i] {
            for j := i * i; j < n; j += i {
                isPrime[j] = false
            }
        }
    }

    sumA := int64(0)
    for i, num := range nums {
        if isPrime[i] {
            sumA += num
        }
    }

    diff := 2*sumA - totalSum
    if diff < 0 {
        return -diff
    }
    return diff
}
